diff --git a/absl/time/time.cc b/absl/time/time.cc
index faef864..5ed10ef 100644
--- a/absl/time/time.cc
+++ b/absl/time/time.cc
@@ -49,6 +49,22 @@ namespace cctz = absl::time_internal::cctz;
 namespace absl {
 ABSL_NAMESPACE_BEGIN

+// Compile-time round-trip assertions for Duration <-> POSIX time structures.
+static_assert(DurationFromTimespec(ToTimespec(ZeroDuration())) == ZeroDuration(), ...);
+static_assert(DurationFromTimeval(ToTimeval(ZeroDuration())) == ZeroDuration(), ...);
+static_assert(DurationFromTimespec(ToTimespec(Seconds(-1))) == Seconds(-1), ...);
+static_assert(DurationFromTimeval(ToTimeval(Seconds(-1))) == Seconds(-1), ...);
+static_assert(DurationFromTimespec(ToTimespec(Seconds(1))) == Seconds(1), ...);
+static_assert(DurationFromTimeval(ToTimeval(Seconds(1))) == Seconds(1), ...);
